-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH current_equipment AS (
    SELECT
        DIM_EQUIPMENT_ID,
        EQPUN_NBR,
        MARK_CD,
        STATUS_CD
    FROM {{ ref('stg_dim_equipment') }}
    WHERE EDW_CURRENT_FLG = 'Y'
),

aar_base_lookup AS (
    SELECT DISTINCT
        EQPMNT_ID,
        EQPUN_NBR,
        MARK_CD
    FROM {{ ref('stg_eqpmnt_aar_base') }}
    WHERE STATUS_CD <> 'I'
      AND DLTD_TMS IS NULL
),

equipment_to_soft_delete AS (
    SELECT
        ce.DIM_EQUIPMENT_ID,
        ce.STATUS_CD,
        ab.EQPMNT_ID
    FROM current_equipment ce
    LEFT JOIN aar_base_lookup ab
        ON TRIM(ce.EQPUN_NBR) = TRIM(ab.EQPUN_NBR)
        AND TRIM(ce.MARK_CD) = TRIM(ab.MARK_CD)
    WHERE ab.EQPMNT_ID IS NULL
       OR ce.STATUS_CD = 'I'
)

SELECT
    DIM_EQUIPMENT_ID,
    '{{ var("repository_user_name", "DBT_USER") }}' AS EDW_UPDATE_USER,
    CURRENT_TIMESTAMP() AS EDW_UPDATE_TMS,
    DATEADD('SECOND', 3661, DATE_TRUNC('DAY', CURRENT_TIMESTAMP())) AS EDW_END_EFCTV_DT,
    'N' AS EDW_CURRENT_FLG
FROM equipment_to_soft_delete
